/**
 * Round-trip parse/serialize tests for all 11 primitive types and ParserActions.
 *
 * Strategy: parse a string S, call getText(false) → T1, parse T1, call getText(false) → T2.
 * Assert T1 === T2 (stability). This proves the serialized form is self-consistent without
 * comparing against Java-generated byte output (which may use different float formatting).
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { DrawingModel } from '../../src/circuit/model/DrawingModel.js';
import { ParserActions } from '../../src/circuit/controllers/ParserActions.js';
import { StandardLayers } from '../../src/layers/StandardLayers.js';
import { Globals } from '../../src/globals/Globals.js';
import { MacroDesc } from '../../src/primitives/MacroDesc.js';

// ---------- helpers ----------

function makeModel(): DrawingModel {
    const m = new DrawingModel();
    m.setLayers(StandardLayers.createStandardLayers());
    return m;
}

function makeParser(model?: DrawingModel): ParserActions {
    return new ParserActions(model ?? makeModel());
}

/** Parse s → getText(false). */
function serialize(s: string): string {
    const pa = makeParser();
    pa.parseString(s);
    return pa.getText(false);
}

/**
 * Stability test: parse S → getText(false) → parse → getText(false).
 * The two serializations must be identical.
 */
function assertStable(s: string): string {
    const t1 = serialize(s);
    const t2 = serialize(t1);
    expect(t2).toBe(t1);
    return t1;
}

// Save/restore Globals so tests don't pollute each other.
let savedDiameter: number;
let savedLineWidth: number;
let savedLineWidthCircles: number;

beforeEach(() => {
    savedDiameter = Globals.diameterConnection;
    savedLineWidth = Globals.lineWidth;
    savedLineWidthCircles = Globals.lineWidthCircles;
});

afterEach(() => {
    Globals.diameterConnection = savedDiameter;
    Globals.lineWidth = savedLineWidth;
    Globals.lineWidthCircles = savedLineWidthCircles;
});

// ---------- PrimitiveLine ----------

describe('PrimitiveLine (LI)', () => {
    it('parses and re-serializes a basic line', () => {
        const out = assertStable('[FIDOCAD]\nLI 10 20 30 40 0\n');
        expect(out).toBe('LI 10 20 30 40 0\n');
    });

    it('preserves non-zero layer', () => {
        const out = assertStable('[FIDOCAD]\nLI 5 5 100 100 3\n');
        expect(out).toBe('LI 5 5 100 100 3\n');
    });

    it('produces empty output for zero-length line (no name/value)', () => {
        const out = serialize('[FIDOCAD]\nLI 50 50 50 50 0\n');
        expect(out).toBe('');
    });

    it('is stable from test size file', () => {
        assertStable('[FIDOCAD]\nFJC C 1.5\nFJC B 0.25\nLI 25 45 110 25 0\n');
    });

    it('round-trips multiple lines', () => {
        const input = '[FIDOCAD]\nLI 80 35 80 45 0\nLI 95 35 95 45 0\nLI 100 35 100 45 0\n';
        assertStable(input);
    });
});

