// ---------- PrimitivePolygon ----------

describe('PrimitivePolygon (PV/PP)', () => {
    it('parses open polygon PV', () => {
        const out = assertStable('[FIDOCAD]\nPV 25 50 65 25 50 85 100 35 100 75 0\n');
        // polygon toString appends a trailing space before layer
        expect(out).toContain('PV ');
        expect(out).toContain('25 50 ');
        expect(out).toContain(' 0\n');
    });

    it('parses filled polygon PP', () => {
        const out = assertStable('[FIDOCAD]\nPP 10 20 30 40 50 60 0\n');
        expect(out).toContain('PP ');
    });

    it('is stable from test size file', () => {
        assertStable('[FIDOCAD]\nFJC C 1.5\nFJC B 0.25\nPV 25 50 65 25 50 85 100 35 100 75 0\n');
    });
});

// ---------- PrimitiveComplexCurve ----------

describe('PrimitiveComplexCurve (CV/CP)', () => {
    it('parses closed filled curve CP', () => {
        const input = '[FIDOCAD]\nCP 1 45 45 70 30 45 60 80 50 75 65 95 30 20 30 65 75 0\n';
        const out = assertStable(input);
        expect(out).toContain('CP ');
        expect(out).toContain('1 ');
    });

    it('parses open unfilled curve CV', () => {
        const input = '[FIDOCAD]\nCV 0 170 130 195 135 200 110 240 115 245 140 215 145 195 100 0\n';
        const out = assertStable(input);
        expect(out).toContain('CV ');
        expect(out).toContain('0 ');
    });

    it('is stable from test size file (open curve)', () => {
        assertStable('[FIDOCAD]\nFJC C 1.5\nFJC A 0.35\nFJC B 0.25\n' +
            'CP 1 45 45 70 30 45 60 80 50 75 65 95 30 20 30 65 75 0\n');
    });

    it('roundtrips a short CV', () => {
        const input = '[FIDOCAD]\nCV 0 240 5 260 25 240 30 0\n';
        const out = assertStable(input);
        expect(out).toBe('CV 0 240 5 260 25 240 30 0\n');
    });
});

