// ---------- PrimitiveAdvText ----------

describe('PrimitiveAdvText (TY/TE)', () => {
    it('parses TY with default font (*)', () => {
        const out = assertStable('[FIDOCAD]\nTY 85 25 5 3 0 0 0 * A\n');
        expect(out).toBe('TY 85 25 5 3 0 0 0 * A\n');
    });

    it('parses TY with named font', () => {
        const out = assertStable('[FIDOCAD]\nTY 35 35 4 3 0 0 0 Helvetica This is a test\n');
        expect(out).toBe('TY 35 35 4 3 0 0 0 Helvetica This is a test\n');
    });

    it('converts TE to TY on output', () => {
        const pa = makeParser();
        pa.parseString('[FIDOCAD]\nTE 10 20 Hello\n');
        const out = pa.getText(false);
        // TE → TY conversion: siy=4, six=3, o=0, sty=0, layer=0
        expect(out).toContain('TY 10 20 4 3 0 0 0 *');
        expect(out).toContain('Hello');
    });

    it('TY output is stable (TY → TY, not TE)', () => {
        // After one parse of TE, output is TY. TY is then stable.
        const pa = makeParser();
        pa.parseString('[FIDOCAD]\nTE 10 20 Hello\n');
        const t1 = pa.getText(false);
        const t2 = serialize(t1);
        expect(t2).toBe(t1);
    });

    it('preserves orientation', () => {
        const out = assertStable('[FIDOCAD]\nTY 225 40 8 3 20 0 0 * Text\n');
        expect(out).toBe('TY 225 40 8 3 20 0 0 * Text\n');
    });

    it('preserves style flags', () => {
        // sty=4 = bold
        const out = assertStable('[FIDOCAD]\nTY 220 10 4 3 0 4 0 * Text\n');
        expect(out).toBe('TY 220 10 4 3 0 4 0 * Text\n');
    });

    it('handles multi-word text', () => {
        const out = assertStable('[FIDOCAD]\nTY 100 100 4 3 0 0 0 * Hello World Foo Bar\n');
        expect(out).toBe('TY 100 100 4 3 0 0 0 * Hello World Foo Bar\n');
    });

    it('is stable from test size file', () => {
        assertStable('[FIDOCAD]\nFJC C 1.5\nFJC B 0.25\nTY 35 35 4 3 0 0 0 Helvetica This is a test\n');
    });
});

// ---------- PrimitiveMacro ----------

describe('PrimitiveMacro (MC)', () => {
    function makeModelWithMacro(key: string, description: string): DrawingModel {
        const model = makeModel();
        const lib = model.getLibrary();
        lib.set(key, new MacroDesc(key, key, description, 'test', 'testlib', 'test.fcl'));
        return model;
    }

    it('parses a macro and re-serializes its key', () => {
        const model = makeModelWithMacro('testmacro', '[FIDOCAD]\nLI 0 0 10 10 0\n');
        const pa = makeParser(model);
        pa.parseString('[FIDOCAD]\nMC 100 100 0 0 testmacro\n');
        const out = pa.getText(false);
        expect(out).toBe('MC 100 100 0 0 testmacro\n');
    });

    it('preserves orientation', () => {
        const model = makeModelWithMacro('mypart', '[FIDOCAD]\nLI 0 0 5 5 0\n');
        const pa = makeParser(model);
        pa.parseString('[FIDOCAD]\nMC 50 50 2 0 mypart\n');
        const out = pa.getText(false);
        expect(out).toBe('MC 50 50 2 0 mypart\n');
    });

    it('preserves mirror flag', () => {
        const model = makeModelWithMacro('widget', '[FIDOCAD]\nLI 0 0 5 5 0\n');
        const pa = makeParser(model);
        pa.parseString('[FIDOCAD]\nMC 30 40 1 1 widget\n');
        const out = pa.getText(false);
        expect(out).toBe('MC 30 40 1 1 widget\n');
    });

    it('is stable (parse → getText → parse → getText)', () => {
        const description = '[FIDOCAD]\nLI 0 0 10 10 0\n';
        const model1 = makeModelWithMacro('part', description);
        const pa1 = makeParser(model1);
        pa1.parseString('[FIDOCAD]\nMC 20 30 0 0 part\n');
        const t1 = pa1.getText(false);

        const model2 = makeModelWithMacro('part', description);
        const pa2 = makeParser(model2);
        pa2.parseString(t1);
        const t2 = pa2.getText(false);

        expect(t2).toBe(t1);
    });

    it('silently skips unknown macros (no library entry)', () => {
        const pa = makeParser();
        // Should not throw; the unknown macro is silently dropped.
        expect(() => pa.parseString('[FIDOCAD]\nMC 80 35 0 0 unknown_macro\n')).not.toThrow();
    });
});

