// ---------- FJC configuration ----------

describe('FJC configuration parsing', () => {
    it('FJC C changes diameterConnection', () => {
        const pa = makeParser();
        pa.parseString('[FIDOCAD]\nFJC C 2.5\n');
        expect(Globals.diameterConnection).toBeCloseTo(2.5);
    });

    it('FJC A changes lineWidth', () => {
        const pa = makeParser();
        pa.parseString('[FIDOCAD]\nFJC A 0.5\n');
        expect(Globals.lineWidth).toBeCloseTo(0.5);
    });

    it('FJC B changes lineWidthCircles', () => {
        const pa = makeParser();
        pa.parseString('[FIDOCAD]\nFJC B 0.25\n');
        expect(Globals.lineWidthCircles).toBeCloseTo(0.25);
    });
});

// ---------- FCJ extension tokens ----------

describe('FCJ extension tokens', () => {
    it('line with FCJ arrow+dash parses without error', () => {
        const input = '[FIDOCAD]\nLI 5 50 90 50 0\nFCJ 0 0 3 2 4 0\n';
        const pa = makeParser();
        expect(() => pa.parseString(input)).not.toThrow();
        // Without extensions=true output, FCJ data is lost but primitive is still there.
        const out = pa.getText(false);
        expect(out).toBe('LI 5 50 90 50 0\n');
    });

    it('bezier with FCJ dash parses without error', () => {
        const input = '[FIDOCAD]\nBE 25 80 20 55 60 55 45 85 0\nFCJ 0 0 0 0 2 0\n';
        const pa = makeParser();
        expect(() => pa.parseString(input)).not.toThrow();
        const out = pa.getText(false);
        expect(out).toBe('BE 25 80 20 55 60 55 45 85 0\n');
    });

    it('rectangle with FCJ fill type parses without error', () => {
        const input = '[FIDOCAD]\nRV 50 20 60 30 0\nFCJ 2 0\n';
        const pa = makeParser();
        expect(() => pa.parseString(input)).not.toThrow();
    });

    it('oval with FCJ fill type parses without error', () => {
        const input = '[FIDOCAD]\nEV 50 5 60 15 0\nFCJ 2 0\n';
        const pa = makeParser();
        expect(() => pa.parseString(input)).not.toThrow();
    });

    it('polygon with FCJ fill type parses without error', () => {
        const input = '[FIDOCAD]\nPV 40 165 85 150 40 185 90 160 0\nFCJ 2 0\n';
        const pa = makeParser();
        expect(() => pa.parseString(input)).not.toThrow();
    });

    it('complex curve with FCJ parses without error', () => {
        const input = '[FIDOCAD]\nCV 0 70 80 90 80 100 105 115 125 105 105 0\nFCJ 3 0 3 2 0 0\n';
        const pa = makeParser();
        expect(() => pa.parseString(input)).not.toThrow();
    });
});

// ---------- addString (incremental parse) ----------

describe('ParserActions.addString', () => {
    it('addString appends to existing primitives', () => {
        const model = makeModel();
        const pa = makeParser(model);
        pa.parseString('[FIDOCAD]\nLI 1 1 2 2 0\n');
        pa.addString('[FIDOCAD]\nRV 3 3 4 4 0\n', false);
        expect(model.getPrimitiveVector()).toHaveLength(2);
    });

    it('parseString clears previous primitives', () => {
        const model = makeModel();
        const pa = makeParser(model);
        pa.parseString('[FIDOCAD]\nLI 1 1 2 2 0\nRV 3 3 4 4 0\n');
        pa.parseString('[FIDOCAD]\nSA 10 10 0\n');
        expect(model.getPrimitiveVector()).toHaveLength(1);
    });
});

// ---------- library round-trip ----------

describe('readLibraryString', () => {
    it('loads a simple library and makes macro parseable', () => {
        const model = makeModel();
        const pa = makeParser(model);
        const libContent = `
{Electronics}
[RLED RLED - Red LED
LI 0 0 10 0 0
LI 10 0 20 0 0
]
`;
        pa.readLibraryString(libContent, 'electronics');
        const lib = model.getLibrary();
        // Key format: prefix.macroname (lowercased)
        const hasLED = [...lib.keys()].some(k => k.includes('rled'));
        expect(hasLED).toBe(true);
    });
});
